let allRows = [];

// 1. Función para limpiar números (Quita comas y convierte a número real)
const limpiarNumero = (valor) => {
  if (typeof valor === 'number') return valor;
  if (!valor || valor === "-") return 0;
  // Quitamos las comas (separadores de miles)
  // Mantenemos el punto si es decimal
  let limpio = valor.toString().replace(/,/g, '');
  return parseFloat(limpio) || 0;
};

let fechaConsultaGlobal = "";
try {
  fechaConsultaGlobal = $("Captura_Fecha_Cartera").first().json.fecha_reporte;
} catch (e) {
  fechaConsultaGlobal = "00/00/0000";
}

for (const item of $input.all()) {
  try {
    const rawContent = item.json.choices[0].message.content;
    const data = JSON.parse(rawContent);

    let detalleUnificado = "";
    if (data.garantia) {
      const listaGarantias = Array.isArray(data.garantia) ? data.garantia : [data.garantia];
      detalleUnificado = listaGarantias.map((g, i) => 
        `Garantía ${i + 1}: ${g.tipo || ''} - ${g.detalle || ''}`
      ).join(' | ');
    }

    const detalles = Array.isArray(data.detalle_financiero) 
      ? data.detalle_financiero 
      : [data.detalle_financiero];

    detalles.forEach(desembolso => {
      const partes = fechaConsultaGlobal.split('/');
      const mes = partes[1] || "00";
      const anio = partes[2] || "0000";

      allRows.push({
        json: {
          Cliente: data.cliente.nombre,
          Identificación: data.cliente.id,
          ActividadEconómica: data.cliente.actividad_economica,
          Operación: data.operacion.id,
          // --- APLICAMOS LIMPIEZA A CAMPOS NUMÉRICOS ---
          SaldoTotal: limpiarNumero(data.operacion.saldo_total),
          PlazoMeses: limpiarNumero(data.operacion.plazo_meses),
          TasaInterés: limpiarNumero(data.operacion.tasa_interes_nm),
          PlanAmortización: data.operacion.plan_amortizacion,
          GarantiaDetalle: detalleUnificado, 
          EstadoGarantia: Array.isArray(data.garantia) ? data.garantia[0].estado : (data.garantia?.estado || null),
          TipoGarantia: Array.isArray(data.garantia) ? data.garantia[0].tipo : (data.garantia?.tipo || null),
          FechaDesembolso: desembolso.fecha_desembolso,
          NumeroRadicado: desembolso.nro_radicado,
          EstadoCapital: desembolso.estado_capital,
          FechaVencimientoCapital: desembolso.fecha_vencimiento_capital,
          ValorDesembolso: limpiarNumero(desembolso.valor_desembolso),
          SaldoCapital: limpiarNumero(desembolso.saldo_capital),
          Vencido: desembolso.vencido,
          DiasVencido: limpiarNumero(desembolso.dias_vencido),
          ValorVencido: limpiarNumero(desembolso.valor_vencido),
          TieneMora: desembolso.tiene_mora,
          ValorMora: limpiarNumero(desembolso.valor_mora),
          FechaUltimoAbono: desembolso.fecha_ultimo_abono,
          ValorUltimoAbono: limpiarNumero(desembolso.valor_ultimo_abono),
          NombreArchivo: `Cartera_${mes}_${anio}.xlsx`
        }
      });
    });
  } catch (e) {
    console.error("Error procesando un ítem: ", e);
  }
}

return allRows;

// Obtenemos todos los items que llegan al nodo
const items = $input.all();

// 1. Ordenamos por nombre de Cliente para que el Excel sea profesional y organizado
items.sort((a, b) => {
  const clienteA = (a.json["Cliente"] || "").toLowerCase();
  const clienteB = (b.json["Cliente"] || "").toLowerCase();
  if (clienteA < clienteB) return -1;
  if (clienteA > clienteB) return 1;
  return 0;
});

// 2. Mantenemos el nombre del archivo que ya viene procesado correctamente
// No necesitamos volver a separar la fecha por '/' porque el nodo anterior ya hizo
// el trabajo de extraer la Fecha de Consulta global.
for (let item of items) {
  // Si por alguna razón el nombre llega vacío, ponemos uno por defecto, 
  // pero ya no usamos la FechaDesembolso para no separar el reporte en años viejos.
  if (!item.json.NombreArchivo) {
    item.json.NombreArchivo = "Cartera_Reporte_General.xlsx";
  }
}

return items;

let allRows = [];

// Función para limpiar números (Quita comas y convierte a número real)
const limpiarNumero = (valor) => {
  if (typeof valor === 'number') return valor;
  if (!valor || valor === "-" || valor === "") return 0;
  // Quitamos las comas (separadores de miles) y convertimos a decimal
  let limpio = valor.toString().replace(/,/g, '');
  return parseFloat(limpio) || 0;
};

for (const item of $input.all()) {
  try {
    // 1. Extraer el contenido del mensaje de Mistral
    const rawContent = item.json.choices[0].message.content;
    const data = JSON.parse(rawContent);

    // 2. Extraer datos generales de la operación
    const operacionNro = data.operacion.nro;
    const tasaDescuento = limpiarNumero(data.operacion.tasa_descuento);
    const fechaOperacion = $("Captura_Fecha_Factoring_Op").first().json.fecha_reporte;
    const cliente = data.operacion.cliente.nombre;
    const clienteNit = data.operacion.cliente.nit;
    const pagador = data.operacion.pagador.nombre;
    const pagadorNit = data.operacion.pagador.nit;
    const netoEntregar = limpiarNumero(data.liquidacion.valor_neto_entregar);

    // 3. Recorrer cada factura en el detalle
    if (data.detalle_facturas && Array.isArray(data.detalle_facturas)) {
      data.detalle_facturas.forEach(fac => {
        allRows.push({
          json: {
            Operacion: operacionNro,
            Cliente: cliente,
            NIT_Cliente: clienteNit,
            Factura_Numero: fac.doc_nro,
            // --- APLICAMOS LIMPIEZA A CAMPOS NUMÉRICOS ---
            Monto: limpiarNumero(fac.valor_neto),
            Dias: limpiarNumero(fac.dias),
            Tasa_Descuento: tasaDescuento,
            Pagador: pagador,
            NIT_Pagador: pagadorNit,
            Fecha_Aprobacion: fechaOperacion,
            Valor_Aprobado: limpiarNumero(fac.valor_presente),
            Valor_Desembolsado: netoEntregar, // Este es el neto de la liquidación general
            Fecha_Desembolso: fac.fecha_inicial,
            Fecha_Vencimiento: fac.fecha_vencimiento,
            Valor_Reserva: limpiarNumero(fac.valor_reserva),
            Descuento_Financiero: limpiarNumero(fac.descuento_financiero),
            // Nombre de archivo sugerido
            NombreArchivo: `Factoring_OP_${operacionNro}.xlsx`
          }
        });
      });
    }
  } catch (e) {
    console.error("Error en Code Extract Factoring: ", e);
  }
}

return allRows;

