let allRows = [];

// Función para limpiar números (Quita comas y convierte a número real)
const limpiarNumero = (valor) => {
  if (typeof valor === 'number') return valor;
  if (!valor || valor === "-" || valor === "" || valor === undefined) return 0;
  // Quitamos las comas (separadores de miles) y convertimos a decimal
  let limpio = valor.toString().replace(/,/g, '');
  return parseFloat(limpio) || 0;
};

for (const item of $input.all()) {
  try {
    const rawContent = item.json.choices[0].message.content;
    const data = JSON.parse(rawContent);

    const opNro = data.operacion.nro;
    const emisor = data.operacion.emisor.nombre;
    const deudor = data.operacion.deudor.nombre;
    const emisorNit = data.operacion.emisor.nit;
    const deudorNit = data.operacion.deudor.nit;
    const factor = limpiarNumero(data.operacion.factor_descuento);

    if (data.detalle_titulos && Array.isArray(data.detalle_titulos)) {
      data.detalle_titulos.forEach(titulo => {
        allRows.push({
          json: {
            Operacion: opNro,
            Emisor: emisor,
            Emisor_Nit: emisorNit,
            Deudor: deudor,
            Deudor_Nit: deudorNit,
            Tasa_Factor: factor,
            ID_Titulo: titulo.id_titulo,
            Fecha_Inicial: titulo.fecha_inicial,
            Fecha_Final: titulo.fecha_final,
            // --- CAMPOS NUMÉRICOS LIMPIOS ---
            Dias: limpiarNumero(titulo.dias),
            Valor_Nominal: limpiarNumero(titulo.vr_nominal),
            Reembolso_G_Desembolso: limpiarNumero(titulo.reembolso_g_desembolso),
            Base_Negociacion: limpiarNumero(titulo.base_negociacion),
            Rendimientos_Proyectados: limpiarNumero(titulo.rend_proyectados),
